			},
			expectError: false,
		},
		{
			name: "valid http endpoint",
			tool: MCPTool{
				Name:     "test-tool",
				Endpoint: "http://localhost:8080",
			},
			expectError: false,
		},
		{
			name: "valid https endpoint",
			tool: MCPTool{
				Name:     "test-tool",
				Endpoint: "https://api.example.com",
			},
			expectError: false,
		},
		{
			name: "empty endpoint",
			tool: MCPTool{
				Name:     "test-tool",
				Endpoint: "",
			},
			expectError: true,
		},
		{
			name: "invalid endpoint scheme",
			tool: MCPTool{
				Name:     "test-tool",
				Endpoint: "ftp://example.com",
			},
			expectError: true,
		},
		{
			name: "empty tool name",
			tool: MCPTool{
				Name:     "",
				Endpoint: "mcp://fs",
			},
			expectError: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.tool.ValidateEndpoint()
			if tt.expectError && err == nil {
				t.Errorf("expected error but got none")
			}
			if !tt.expectError && err != nil {
				t.Errorf("expected no error but got: %v", err)
			}
		})
	}
}

func TestMCPBudgets_ValidateTimeout(t *testing.T) {
	tests := []struct {
		name        string
		budgets     MCPBudgets
		expectError bool
		expected    time.Duration
	}{
		{
			name: "valid timeout",
			budgets: MCPBudgets{
				Timeout: "30m",
			},
			expectError: false,
			expected:    30 * time.Minute,
		},
		{
			name:        "empty timeout uses default",
			budgets:     MCPBudgets{},
			expectError: false,
			expected:    30 * time.Minute,
		},
		{
			name: "invalid timeout format",
			budgets: MCPBudgets{
				Timeout: "invalid",
			},
			expectError: true,
		},
		{
			name: "negative timeout",
			budgets: MCPBudgets{
				Timeout: "-5m",
			},
			expectError: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			duration, err := tt.budgets.ValidateTimeout()
			if tt.expectError && err == nil {
				t.Errorf("expected error but got none")
			}
			if !tt.expectError && err != nil {
				t.Errorf("expected no error but got: %v", err)
			}
			if !tt.expectError && duration != tt.expected {
				t.Errorf("expected duration %v but got %v", tt.expected, duration)
			}
		})
	}
}

